-- ============================================================================
-- NEW YORK development_reports seed — REPRODUCIBLE pg_net REFRESH SCRIPT
-- (pattern: docs/massachusetts-development-reports-seed.sql; run in the Supabase SQL editor)
--
-- Built 2026-07-15: all 764 modeled NY ZIPs (the 519-ZIP statewide build + the
-- FIVE-BOROUGH EXPANSION — migration nyc_borough_zip_expansion: New York/Kings/Queens/
-- Bronx/Richmond county roots + 245 zip pages; 10470 pre-existing under Westchester)
-- cached through the live engine and materialized into app_*. Development depth from
-- TWO first-party sources wired this pass: nyc-dobnow-approved-permits (Socrata
-- rbx6-tga4, fresh same-day, 5 of 21 verbatim work_types kept) and
-- nyc-dob-permit-issuance (ipu4-2q9a BIS legacy, still daily, NB/DM/AL/FO whitelist).
-- Buffalo (403 restricted views), Syracuse (stalled 2025-08-16 -> reprobe), Rochester/
-- Albany/NYS/LI+Westchester rejected with receipts (docs/source-registry.md "NEW YORK
-- WIRE PASS"). Centroids pinned to zipcodes PyPI v3.0.0; 0 quarantined. INDEX POLICY:
-- substance gate stamps indexable automatically; throttled sitemap (250/day) — no manual flip.
-- ============================================================================
drop table if exists public._ny_zips;
create table public._ny_zips(zip text primary key, lat float8, lng float8);

-- FIRE in waves of ~90 (offsets 0..720; wait ~2.5 min per wave) ----------------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', zip, 'lat', lat, 'lng', lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 120000)) as fired
from (select * from public._ny_zips order by zip limit 90 offset 0) w;

-- COLLECT after each wave (transient-safe upsert) -----------------------------------
select (j->>'zip'), (j->'home'->>'lat')::float8, (j->'home'->>'lng')::float8, j->'counts', j->'sites',
       coalesce((j->>'paywall')::bool,false),
       'zipcodes PyPI v3.0.0 centroid; get-address-report ZIP mode; New York batch 2026-07-15',
       now()
from (
  select distinct on ((content::jsonb->>'zip')) content::jsonb j
  from net._http_response resp
  where resp.status_code = 200 and left(ltrim(resp.content),1)='{'
    and (content::jsonb->>'zip') in (select zip from public._ny_zips)
    and resp.created > now() - interval '30 minutes'
  order by (content::jsonb->>'zip'), resp.created desc
) r
on conflict (zip) do update set home_lat=excluded.home_lat, home_lng=excluded.home_lng,
  counts=excluded.counts, sites=excluded.sites, paywall=excluded.paywall,
  source_vintage=excluded.source_vintage, refreshed_at=excluded.refreshed_at
where jsonb_array_length(excluded.sites) > 0 or jsonb_array_length(public.development_reports.sites) = 0;

-- RE-FIRE stragglers (180s), re-collect; MATERIALIZE + verify ------------------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', z.zip, 'lat', z.lat, 'lng', z.lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 180000)) as refired
from public._ny_zips z
where not exists (select 1 from public.development_reports dr where dr.zip = z.zip);
select public.app_refresh_all();
select (select count(*) from public.development_reports dr join public._ny_zips z on z.zip=dr.zip) as ny_cached,
       (select count(*) from public.app_community_meta m join public._ny_zips z on z.zip=m.zip where m.indexable) as ny_indexable;
